<?php
namespace App\Modules\Hr\Advance\Livewire;
use App\Modules\Hr\Advance\Actions\CancelAdvanceAction; use App\Modules\Hr\Advance\Actions\CreateAdvanceAction; use App\Modules\Hr\Advance\Actions\DecideAdvanceAction; use App\Modules\Hr\Advance\Actions\PayAdvanceAction; use App\Modules\Hr\Advance\Actions\RecordAdvanceRepaymentAction; use App\Modules\Hr\Advance\Enums\AdvanceTransactionType; use App\Modules\Hr\Advance\Models\HrAdvance; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Str; use Livewire\Component; use Livewire\WithPagination;
class AdvanceWorkspace extends Component { use WithPagination; public bool $selfService=false; public ?int $employeeId=null; public string $requestedAmount=''; public string $currency='TRY'; public int $installmentCount=1; public string $requestedPaymentDate=''; public string $reason=''; public string $sourceKey=''; public string $search=''; public string $statusFilter=''; public string $sortField='requested_payment_date'; public string $sortDirection='desc'; public array $visibleColumns=['employee','date','amount','installments','balance','status','actions']; public ?int $decidingId=null; public string $decisionNote=''; public ?int $payingId=null; public string $paymentReference=''; public ?int $repayingId=null; public string $repaymentAmount=''; public string $repaymentReference=''; public string $repaymentType='repayment'; public const COLUMNS=['employee'=>'Çalışan','date'=>'Ödeme tarihi','amount'=>'Talep','installments'=>'Taksit','balance'=>'Kalan','status'=>'Durum','actions'=>'İşlem']; private const SORTABLE=['requested_payment_date','requested_amount','status','created_at'];
public function mount(bool $selfService=false):void{$this->selfService=$selfService;$this->requestedPaymentDate=now()->addWeek()->toDateString();$this->sourceKey=(string)Str::uuid();if($selfService)$this->employeeId=$this->ownEmployee()->id;}
public function create(CreateAdvanceAction $action):void{$this->validate(['employeeId'=>'required|integer','requestedAmount'=>'required|numeric|min:0.01','currency'=>'required|in:TRY,EUR,USD,GBP','installmentCount'=>'required|integer|min:1|max:36','requestedPaymentDate'=>'required|date','reason'=>'required|string|max:2000']);$action->execute($this->employee($this->employeeId),['requested_amount'=>$this->requestedAmount,'currency'=>$this->currency,'installment_count'=>$this->installmentCount,'requested_payment_date'=>$this->requestedPaymentDate,'reason'=>$this->reason],$this->sourceKey);$this->reset(['requestedAmount','reason']);$this->installmentCount=1;$this->sourceKey=(string)Str::uuid();if($this->selfService)$this->employeeId=$this->ownEmployee()->id;session()->flash('success','Avans talebi oluşturuldu.');}
public function startDecision(int $id):void{$this->advance($id);$this->decidingId=$id;$this->decisionNote='';} public function approve(DecideAdvanceAction $a):void{$a->approve($this->advance($this->decidingId),$this->decisionNote?:null);$this->reset(['decidingId','decisionNote']);} public function reject(DecideAdvanceAction $a):void{$this->validate(['decisionNote'=>'required|string|max:1000']);$a->reject($this->advance($this->decidingId),$this->decisionNote);$this->reset(['decidingId','decisionNote']);} public function startPayment(int $id):void{$this->payingId=$this->advance($id)->id;$this->paymentReference='';} public function pay(PayAdvanceAction $a):void{$this->validate(['paymentReference'=>'required|string|max:160']);$a->execute($this->advance($this->payingId),$this->paymentReference);$this->reset(['payingId','paymentReference']);} public function startRepayment(int $id):void{$advance=$this->advance($id);$this->repayingId=$id;$this->repaymentAmount=$advance->outstanding_amount;$this->repaymentReference='';} public function repay(RecordAdvanceRepaymentAction $a):void{$this->validate(['repaymentAmount'=>'required|numeric|min:0.01','repaymentReference'=>'required|string|max:160','repaymentType'=>'required|in:repayment,payroll_deduction']);$a->execute($this->advance($this->repayingId),(float)$this->repaymentAmount,$this->repaymentReference,AdvanceTransactionType::from($this->repaymentType));$this->reset(['repayingId','repaymentAmount','repaymentReference']);} public function cancel(int $id,CancelAdvanceAction $a):void{$a->execute($this->advance($id));}
public function sortTable(string $field):void{abort_unless(in_array($field,self::SORTABLE,true),422);if($this->sortField===$field)$this->sortDirection=$this->sortDirection==='asc'?'desc':'asc';else{$this->sortField=$field;$this->sortDirection='asc';}} public function toggleColumn(string $key):void{abort_unless(isset(self::COLUMNS[$key]),422);if(in_array($key,['employee','actions'],true))return;$this->visibleColumns=in_array($key,$this->visibleColumns,true)?array_values(array_diff($this->visibleColumns,[$key])):array_values(array_intersect(array_keys(self::COLUMNS),[...$this->visibleColumns,$key]));}
public function render(){$tenant=app(TenantContext::class)->getId();$q=HrAdvance::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->with(['employee','transactions']);if($this->selfService)$q->where('employee_id',$this->ownEmployee()->id);elseif($this->search!=='')$q->whereHas('employee',fn($e)=>$e->search($this->search));if($this->statusFilter!=='')$q->where('status',$this->statusFilter);return view('livewire.hr.advance.advance-workspace',['advances'=>$q->orderBy($this->sortField,$this->sortDirection)->paginate(20),'employees'=>HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->active()->orderBy('first_name')->get(),'columnLabels'=>self::COLUMNS])->layout('layouts.app');} private function ownEmployee():HrEmployee{return HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->where('user_id',auth()->id())->firstOrFail();} private function employee(int $id):HrEmployee{return HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);} private function advance(?int $id):HrAdvance{abort_unless($id,404);return HrAdvance::withoutGlobalScope('tenant')->where('legal_entity_id',app(TenantContext::class)->getId())->findOrFail($id);} }
